var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"역신 오로치를 막기 위해 많은 희생이 있었다.","JPN":"疫病神オロチを止めるため多くの犠牲があった。","ENG":"There were many sacrifices in order to stop Orochi, the Plague God.","TWN":"因為要阻止瘟神大蛇而造成許多犧牲。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"긴 싸움 끝에 명부신이 오로치의 목을 베었지만, 이미 세상은 역신의 독으로 무너지고 있었다.","JPN":"長い戦いの末に冥府の神がオロチの首を打ったが、すでに世界は疫病神の毒で崩れかけていた。","ENG":"After what seemed like an endless battle, the Nether God finally succeeded in slaying Orochi’s head. But the world was already destroyed by the Plague God’s poison.","TWN":"經過漫長的抗爭，冥府神最終斬下大蛇的頭，世界卻已經因為瘟神的毒而崩塌。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"명부신은 자신의 세 자손을 한 자리에 불러모아, 세 가지 재앙을 예견하고 이에 대비하도록 했다.","JPN":"冥府の神は三人の子孫を呼び寄せ、三つの災いを予言してそれに備えさせた。","ENG":"So the Nether God brought together his three descendants and predicted three catastrophes, to make them prepare for the inevitable.","TWN":"冥府神於是召聚三個兒子，並預言會有三個災難，要他們為此做好準備。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"세 자손은 그 유언을 받들어 명부신의 영혼으로 옥을 빗고, 역신의 비늘로 검을 만들었다.","JPN":"三人の子孫はその遺言に従い冥府の神の魂で宝玉を作り、疫病神の鱗で剣を作った。","ENG":"The three descendants took his will, shaping his soul into a sacred jade, while also using his scales to make a sword.","TWN":"三個兒子聽完冥府神的遺言後，將其靈魂凝聚成玉石，並且用瘟神的鱗片打造出一把寶劍。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그중 하나가 지금의 나나하라 영지에 숨겨진 결계옥.","JPN":"そのうちの一つが現在七原領地内に隠されておる結界玉。","ENG":"The jade is Akaitama hidden in the Nanahara estate.","TWN":"其中一個就是目前藏在七原領地裡的結界玉石。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"다른 하나는 나나하라 가문 대대로 물려져 내려오는 천총운검이지.","JPN":"もう一つは七原家に代々伝わる天叢雲剣じゃ。","ENG":"The other is the Sword of Kusanagi, passed down for generation within the Nanahara family.","TWN":"另一個就是七原家族代代相傳的天叢雲劍。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"첫째는 봉인역의 결계를 지키기 위해. 둘째는 오로치를 막기 위한 것이죠.","JPN":"一つ目は封印域の結界を守るための。二つ目はオロチを阻止するためのものですね。","ENG":"The former is to protect the Seal Domain, and the latter is to stop Orochi.","TWN":"玉石的功用是保護封印域的結界，寶劍的用途則是抵抗大蛇。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하지만 세번째 신기인 역신베기는 그 생김새와 쓰임새에 대해 들어본 적도 없습니다.","JPN":"ですが三つ目の神器である大蛇薙剣はその形や使い道について聞いたことがございません。","ENG":"But never have I heard of the usage and appearance of Orochinagi.","TWN":"不過第三個神器瘟神斬，我卻從未聽說過它的樣子和用途。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그야 아직 완성되지 못했으니 그러지.","JPN":"そりゃあまだ完成していないからのう。","ENG":"That’s because it’s not completed yet.","TWN":"那是因為還沒完成的關係。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네? 그렇다면…… 세번째로 예견된 재앙을 막는 법이 없는 건가요?","JPN":"はい？　でしたら……予言された三度目の災いを止める方法はないのですか？","ENG":"What? Then... is there no way to stop the third catastrophe from happening?","TWN":"什麼？所以意思是……目前沒有方法可以阻止預言的第三個災難嗎？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"내 선조는 오랫동안 역신베기의 마지막 재료를 찾기 위해 노력했다.","JPN":"わしの先祖は長らく大蛇薙剣の最後の材料を探すために頑張ってきたのだが。","ENG":"For years, my ancestors have searched for the last component in finishing Orochinagi.","TWN":"我的祖先一直在努力尋找瘟神斬最後的材料。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"하지만 끝내 찾아내지 못했고, 내가 그 유지를 잇고자 이곳에 온 게다.","JPN":"結局見つからず、今回わしがその遺志を受け継いでここへ来たというわけじゃ。","ENG":"But they never did. Thus here I am to success their will.","TWN":"但始終沒能找到，而我則是繼承祖先的遺願才會來到這裡。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그렇다면 말씀해주세요.","JPN":"それなら、どうぞおしゃってください。","ENG":"Please tell me.","TWN":"那請告訴我，"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저희가 어떤 도움을 드리면 되겠습니까?","JPN":"私たちがどのようにお手伝いしたらいいのですか？","ENG":"How can we help you?","TWN":"我們該如何幫您呢？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"역신베기는 두려워 할 죽음이 없는 무사가 자신의 목숨을 바쳐 완성되리라.","JPN":"大蛇薙剣は恐れるべき死のない武士が自らの命を捧げることにより完成するであろう。","ENG":"Completed shall Orochinagi be, with the life of a warrior unafraid of all death.","TWN":"瘟神斬必須由無懼死亡的武士獻上自己的性命才能完成。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그것이 명부신께서 예견한 역신베기의 조건이지.","JPN":"それが冥府の神が予言なさった大蛇薙剣の条件じゃ。","ENG":"That is the prerequisite of completing Orochinagi.","TWN":"這是完成瘟神斬的條件。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"목숨이라 함은…… 설마 희생을 의미하는 것인가요?","JPN":"命と申しますと……まさか犠牲を意味しているのですか？","ENG":"\\"With the life\\"... Do you mean sacrifices?","TWN":"性命……該不會是要犧牲性命吧？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"어린 것이 이해가 빨라서 좋구나.","JPN":"物わかりの良い子じゃのう。","ENG":"You’re quite bright for your young age.","TWN":"你的反應很快呢，很好。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"죄송하지만, 그렇게 할 수 없습니다.","JPN":"申し訳ありませんが、それはできません。","ENG":"I’m sorry, but that won’t be possible.","TWN":"抱歉，那恕我們幫不上忙。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};